'use server'

import { createClient } from '@/lib/supabase/server'
import { revalidatePath } from 'next/cache'
import { InventoryItem, InventoryItemInsert, InventoryItemUpdate, InventoryBatch, InventoryBatchInsert, Supplier } from '@/types/inventory'

export async function getInventoryItems() {
    const supabase = await createClient()

    // Fetch items with their batches to calculate total quantity
    const { data, error } = await supabase
        .from('inventory_items')
        .select(`
      *,
      batches:inventory_batches(
        id, quantity, expiration_date, batch_number, is_active
      )
    `)
        .order('name')

    if (error) {
        console.error('Error fetching inventory:', error)
        return []
    }

    // Calculate total quantity for each item
    const items = data.map((item: any) => ({
        ...item,
        total_quantity: item.batches?.reduce((acc: number, batch: any) => acc + (batch.is_active ? batch.quantity : 0), 0) || 0
    }))

    return items as InventoryItem[]
}

export async function createInventoryItem(data: InventoryItemInsert) {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) throw new Error('Unauthorized')

    const { data: newItem, error } = await supabase
        .from('inventory_items')
        .insert({ ...data, user_id: user.id } as never)
        .select()
        .single()

    if (error) throw new Error(error.message)

    revalidatePath('/inventory')
    return newItem as InventoryItem
}

export async function updateInventoryItem(id: string, data: InventoryItemUpdate) {
    const supabase = await createClient()

    const { error } = await supabase
        .from('inventory_items')
        .update(data as never)
        .eq('id', id)

    if (error) throw new Error(error.message)

    revalidatePath('/inventory')
}

export async function deleteInventoryItem(id: string) {
    const supabase = await createClient()

    // Usually we might check for dependencies/movements before deleting
    const { error } = await supabase
        .from('inventory_items')
        .delete()
        .eq('id', id)

    if (error) throw new Error(error.message)

    revalidatePath('/inventory')
}

export async function getSuppliers() {
    const supabase = await createClient()
    const { data, error } = await supabase
        .from('inventory_suppliers') // Assuming table name
        .select('*')
        .order('name')

    if (error) return [] // Soft fail if table doesn't exist yet
    return data as Supplier[]
}

// Batches
export async function addBatch(data: InventoryBatchInsert) {
    const supabase = await createClient()

    const { data: batch, error } = await supabase
        .from('inventory_batches')
        .insert(data as never)
        .select()
        .single()

    if (error) throw new Error(error.message)
    revalidatePath('/inventory')
    return batch as InventoryBatch
}
